(2, 'OEO0002', 'One Earth Organics – Illumina Milk Soap', 'For instant whiter, softer, and more radiant looking skin', NULL, NULL, 500.00, NULL, 1, NULL, NULL, NULL, NULL, 1, 1, '2025-05-10 17:07:22', '2025-09-29 14:50:54', 'src/images/products/uploads/681f174adf140_Screenshot 2025-05-10 170236.png', 'src/images/products/uploads/681f174adedcb_Screenshot 2025-05-10 170236.png', NULL, 'src/images/products/uploads/681f174adf4ad_Screenshot 2025-05-10 170236.png', 0),
