(4, 'ORS00004', 'Oil Regulating Soap – Azelane', 'Helps by gently cleansing dirt and oil build-up on the skin, leaving the skin feeling refreshed.', NULL, NULL, 350.00, NULL, 1, NULL, NULL, NULL, NULL, 1, 1, '2025-05-10 17:10:53', '2025-09-29 14:51:07', 'src/images/products/uploads/681f181d83b0d_Screenshot 2025-05-10 170335.png', 'src/images/products/uploads/681f181d836f4_Screenshot 2025-05-10 170335.png', NULL, 'src/images/products/uploads/681f181d83f94_Screenshot 2025-05-10 170335.png', 0),
(5, 'DT00001', 'Dermorepubliq 0.3% Microencapsulated Retinol + Backuchiol + Ceramide NP Face Cream', 'This luxurious, lightweight cream is formulated with a powerful combination of ingredients to address various skin concerns with gentle yet effective care.', NULL, NULL, 500.00, NULL, 4, NULL, NULL, NULL, NULL, 1, 1, '2025-05-10 17:11:50', '2025-09-29 14:51:15', 'src/images/products/uploads/681f1856cdba0_Screenshot 2025-05-10 170405.png', 'src/images/products/uploads/681f1856cd64d_Screenshot 2025-05-10 170405.png', NULL, 'src/images/products/uploads/681f1856cdf53_Screenshot 2025-05-10 170405.png', 0),
(6, 'HYSUN000012', 'SKIN&LAB Hybarrier Fresh Sun Lotion SFP 50', 'Can be used for the face or body, the easy application also makes it an amazing choice for outdoor activities lovers.', NULL, NULL, 250.00, NULL, 5, NULL, NULL, NULL, NULL, 1, 0, '2025-05-10 17:12:56', '2025-05-11 11:12:42', 'src/images/products/uploads/681f18984cef8_Screenshot 2025-05-10 170436.png', 'src/images/products/uploads/681f18984c99f_Screenshot 2025-05-10 170436.png', NULL, 'src/images/products/uploads/681f18984d33f_Screenshot 2025-05-10 170436.png', 0),
(7, 'BELSPRAY00011', 'BELFOUR Underarm Spray Intense White', 'Spray Intense White provides long lasting natural protection from body odor and gives a feeling of freshness and dryness that last all day.', NULL, NULL, 150.00, NULL, 6, NULL, NULL, NULL, NULL, 1, 0, '2025-05-10 17:14:02', '2025-05-11 11:12:42', 'src/images/products/uploads/681f18da1502f_Screenshot 2025-05-10 170451.png', 'src/images/products/uploads/681f18da14bec_Screenshot 2025-05-10 170451.png', NULL, 'src/images/products/uploads/681f18da153ed_Screenshot 2025-05-10 170451.png', 0),
(8, 'PICO0001', 'Pico-Diode Underarm Laser', 'It boosts elastin production, creating a softer, fuller, and more youthful complexion. The Pico laser uses ultra-short energy pulses to target problem areas without heat, breaking down unwanted pigments or particles in the skin.', NULL, NULL, 690.00, NULL, 7, NULL, NULL, NULL, NULL, 1, 0, '2025-05-10 17:15:13', '2025-05-10 17:15:13', 'src/images/products/uploads/681f192147624_Screenshot 2025-05-10 170515.png', 'src/images/products/uploads/681f1921470c6_Screenshot 2025-05-10 170515.png', NULL, 'src/images/products/uploads/681f192147af6_Screenshot 2025-05-10 170515.png', 2),
(9, 'SKINPELLING0001', 'Skin Peeling', 'This treatment improves skin elasticity, smoothness, and hydration while reducing photoaging, wrinkles, and expression lines for a healthier, more youthful complexion.', NULL, NULL, 400.00, NULL, 7, NULL, NULL, NULL, NULL, 1, 0, '2025-05-10 17:15:56', '2025-05-10 17:15:56', 'src/images/products/uploads/681f194c87724_Screenshot 2025-05-10 170531.png', 'src/images/products/uploads/681f194c873ad_Screenshot 2025-05-10 170531.png', NULL, 'src/images/products/uploads/681f194c87b76_Screenshot 2025-05-10 170531.png', 2),
(10, 'DIAMOND000011', 'Diamond Peel', 'Gently exfoliates the skin, removing dead cells to reveal a smoother, brighter complexion. It improves skin texture, minimizes pores, reduces fine lines, and fades dark spots.', NULL, NULL, 350.00, NULL, 7, NULL, NULL, NULL, NULL, 1, 0, '2025-05-10 17:17:20', '2025-05-10 17:17:20', 'src/images/products/uploads/681f19a08c8ab_Screenshot 2025-05-10 170550.png', 'src/images/products/uploads/681f19a08c546_Screenshot 2025-05-10 170550.png', NULL, 'src/images/products/uploads/681f19a08cc70_Screenshot 2025-05-10 170550.png', 2),
(11, 'WARTREMOVAL011111', 'Cautery Warts Removal', 'Effectively eliminates warts by using controlled heat to destroy the affected tissue. This treatment is quick, minimizes discomfort, and prevents the spread of warts, leaving the skin smoother and healthier.', NULL, NULL, 750.00, NULL, 7, NULL, NULL, NULL, NULL, 1, 0, '2025-05-10 17:18:12', '2025-05-10 17:18:12', 'src/images/products/uploads/681f19d4b6748_Screenshot 2025-05-10 170615.png', 'src/images/products/uploads/681f19d4b63b4_Screenshot 2025-05-10 170615.png', NULL, 'src/images/products/uploads/681f19d4b6ac3_Screenshot 2025-05-10 170615.png', 2),
(12, 'ILLUMINA', 'Skin Whitening – Illumina Body Soap ', 'Helps to brighten the skin and treat acne breakouts. ', NULL, NULL, 500.00, NULL, 1, NULL, NULL, NULL, NULL, 1, 1, '2025-05-13 14:09:59', '2025-05-13 14:46:51', 'src/images/products/uploads/6822e237af2e0_Screenshot 2025-05-13 140650.png', 'src/images/products/uploads/6822e237af056_Screenshot 2025-05-13 140650.png', NULL, 'src/images/products/uploads/6822e237af3f0_Screenshot 2025-05-13 140650.png', 0),
(13, 'ILLUMINA02', 'One Earth Organics – Illumina Milk Soap', 'For instant whiter, softer, and more radiant looking skin', NULL, NULL, 500.00, NULL, 1, NULL, NULL, NULL, NULL, 1, 1, '2025-05-13 14:39:01', '2025-05-13 14:46:59', 'src/images/products/uploads/6822e905b6a69_Screenshot 2025-05-13 143846.png', 'src/images/products/uploads/6822e905b6831_Screenshot 2025-05-13 143846.png', NULL, 'src/images/products/uploads/6822e905b6bde_Screenshot 2025-05-13 143846.png', 0),
