(16, 'FACECREAM', 'Dermorepubliq 0.3% Microencapsulated Retinol + Backuchiol + Ceramide NP Face Cream', 'This luxurious, lightweight cream is formulated with a powerful combination of ingredients to address various skin concerns with gentle yet effective care.', NULL, NULL, 500.00, NULL, 4, NULL, NULL, NULL, NULL, 1, 1, '2025-05-13 14:42:43', '2025-05-13 14:47:19', 'src/images/products/uploads/6822e9e3eec3e_Screenshot 2025-05-13 144219.png', 'src/images/products/uploads/6822e9e3eea56_Screenshot 2025-05-13 144219.png', NULL, 'src/images/products/uploads/6822e9e3eed75_Screenshot 2025-05-13 144219.png', 0),
(17, 'TONER01', 'Dermorepubliq Duos - Dark Spots', 'This concentrated, ultra-whitening Alpha Arbutin Toner + Tranexamic Acid helps reduce the appearance of hyperpigmentation, dark spots, and acne scars. It is an advanced skin-brightening & lightening formula.', NULL, NULL, 900.00, NULL, 2, NULL, NULL, NULL, NULL, 1, 1, '2025-05-13 14:50:23', '2025-09-29 14:51:23', 'src/images/products/uploads/6822ebaf7207b_Screenshot 2025-05-13 144844.png', 'src/images/products/uploads/6822ebaf71e2a_Screenshot 2025-05-13 144844.png', NULL, 'src/images/products/uploads/6822ebaf72270_Screenshot 2025-05-13 144844.png', 0),
(18, 'SERUM01', 'BREYLEE - Vitamin C Serum', 'Containing high activity small-molecule Vitamin C, with antioxidant protection, this product can prevent melanin formation.', NULL, NULL, 800.00, NULL, 3, NULL, NULL, NULL, NULL, 1, 1, '2025-05-13 14:51:40', '2025-09-29 14:51:29', 'src/images/products/uploads/6822ebfcd4c13_Screenshot 2025-05-13 145128.png', 'src/images/products/uploads/6822ebfcd4a39_Screenshot 2025-05-13 145128.png', NULL, 'src/images/products/uploads/6822ebfcd4d7f_Screenshot 2025-05-13 145128.png', 0),
(19, 'CREAM01', 'LANEIGE - Radian-C Cream', 'Vitamin cream that hydrates skin and improves dark spots, redness and uneven skin tone for brightening and radiant complexion.', NULL, NULL, 650.00, NULL, 1, NULL, NULL, NULL, NULL, 1, 1, '2025-05-13 14:52:35', '2025-09-29 14:51:38', 'src/images/products/uploads/6822ec3351d88_Screenshot 2025-05-13 145158.png', 'src/images/products/uploads/6822ec3351b1e_Screenshot 2025-05-13 145158.png', NULL, 'src/images/products/uploads/6822ec3351ec6_Screenshot 2025-05-13 145158.png', 2),
